// ============================================================
// Node 5: Parse Message
// Extracts sender phone, message type, text/media/flow data
// from the Meta WhatsApp Cloud API webhook payload.
// ============================================================

const body = $input.first().json.body;

// Safety: only process actual messages, ignore status updates
const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;
const message = value?.messages?.[0];

if (!message) {
  return [{ json: { skip: true } }];
}

const senderPhone = message.from;
const messageId = message.id;
const messageType = message.type; // text, document, image, interactive

let messageText = '';
let mediaId = '';
let mediaMimeType = '';
let mediaFileName = '';
let flowResponseData = null;

if (messageType === 'text') {
  messageText = message.text?.body || '';
} else if (messageType === 'interactive') {
  const interactive = message.interactive;
  if (interactive?.type === 'button_reply') {
    messageText = interactive.button_reply.id;
  } else if (interactive?.type === 'nfm_reply') {
    try {
      flowResponseData = JSON.parse(interactive.nfm_reply.response_json);
    } catch (e) {
      flowResponseData = null;
    }
  }
} else if (messageType === 'document') {
  mediaId = message.document.id;
  mediaMimeType = message.document.mime_type || '';
  mediaFileName = message.document.filename || 'document';
} else if (messageType === 'image') {
  mediaId = message.image.id;
  mediaMimeType = message.image.mime_type || 'image/jpeg';
  mediaFileName = 'image.jpg';
}

return [{
  json: {
    skip: false,
    senderPhone,
    messageId,
    messageType,
    messageText,
    mediaId,
    mediaMimeType,
    mediaFileName,
    flowResponseData,
  }
}];

// ============================================================
// Node 6: State Machine
// Manages conversational state per phone number.
// Uses $getWorkflowStaticData('global') for persistence.
// ============================================================

// ==================== CONFIGURATION ==========================
// Replace these values with your actual credentials:
const WHATSAPP_PHONE_NUMBER_ID = 'YOUR_PHONE_NUMBER_ID';
const WHATSAPP_ACCESS_TOKEN = 'YOUR_WHATSAPP_ACCESS_TOKEN';
const BACKEND_API_URL = 'https://tenant.amprosystem.com/api';
const BACKEND_AUTH_TOKEN = 'YOUR_BACKEND_AUTH_TOKEN';
const CLIENT_FLOW_ID = 'YOUR_CLIENT_FLOW_ID';
const PROJECT_FLOW_ID = 'YOUR_PROJECT_FLOW_ID';
const CONFIG_FLOW_ID = 'YOUR_CONFIG_FLOW_ID';
// =============================================================

const input = $input.first().json;

if (input.skip) {
  return [{ json: { action: 'no_op' } }];
}

const {
  senderPhone, messageType, messageText,
  mediaId, mediaMimeType, mediaFileName, flowResponseData
} = input;

// Persistent state per phone number
const globalData = $getWorkflowStaticData('global');
if (!globalData.conversations) {
  globalData.conversations = {};
}
if (!globalData.conversations[senderPhone]) {
  globalData.conversations[senderPhone] = { state: 'new' };
}

const conv = globalData.conversations[senderPhone];
const state = conv.state;

let action = 'no_op';
let payload = {};

const WA_URL = `https://graph.facebook.com/v21.0/${WHATSAPP_PHONE_NUMBER_ID}/messages`;

switch (state) {

  // ---- NEW: greet and ask to start ----
  case 'new': {
    action = 'send_buttons';
    payload = {
      to: senderPhone,
      body: 'Welcome! Would you like to generate a quotation?',
      buttons: [
        { id: 'yes', title: 'Yes' },
        { id: 'no', title: 'No' },
      ],
    };
    conv.state = 'awaiting_confirm';
    break;
  }

  // ---- AWAITING CONFIRM ----
  case 'awaiting_confirm': {
    if (messageText === 'yes') {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: 'Please send your BOQ file.\n\nAccepted formats:\n- Excel (.xlsx)\n- PDF (.pdf)\n- Images (you can send multiple)',
      };
      conv.state = 'awaiting_boq';
    } else if (messageText === 'no') {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: 'No problem! Send me a message anytime to start.',
      };
      conv.state = 'new';
    } else {
      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: 'Please tap one of the buttons below.',
        buttons: [
          { id: 'yes', title: 'Yes' },
          { id: 'no', title: 'No' },
        ],
      };
    }
    break;
  }

  // ---- AWAITING BOQ ----
  case 'awaiting_boq': {
    if (messageType === 'document') {
      const isXlsx = mediaMimeType.includes('spreadsheet') ||
                     mediaMimeType.includes('excel') ||
                     mediaFileName.endsWith('.xlsx');
      const isPdf = mediaMimeType === 'application/pdf' ||
                    mediaFileName.endsWith('.pdf');

      if (isXlsx || isPdf) {
        conv.boq_media_id = mediaId;
        conv.boq_media_type = isPdf ? 'pdf' : 'xlsx';
        conv.boq_filename = mediaFileName;
        conv.boq_mime_type = mediaMimeType;

        action = 'send_text';
        payload = {
          to: senderPhone,
          text: 'BOQ file received.\n\nNow please send your Specification file (PDF only).',
        };
        conv.state = 'awaiting_spec';
      } else {
        action = 'send_text';
        payload = {
          to: senderPhone,
          text: 'Unsupported file format. Please send an Excel (.xlsx) or PDF (.pdf) file.',
        };
      }
    } else if (messageType === 'image') {
      conv.boq_images = [{ media_id: mediaId, mime_type: mediaMimeType }];
      conv.boq_media_type = 'images';

      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: 'Image received! Send more images or tap Done.',
        buttons: [
          { id: 'more_images', title: 'Send More' },
          { id: 'done_images', title: 'Done' },
        ],
      };
      conv.state = 'collecting_boq_images';
    } else {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: 'Please send a BOQ file (Excel, PDF, or images).',
      };
    }
    break;
  }

  // ---- COLLECTING BOQ IMAGES ----
  case 'collecting_boq_images': {
    if (messageType === 'image') {
      conv.boq_images.push({ media_id: mediaId, mime_type: mediaMimeType });

      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: `${conv.boq_images.length} image(s) received. Send more or tap Done.`,
        buttons: [
          { id: 'more_images', title: 'Send More' },
          { id: 'done_images', title: 'Done' },
        ],
      };
    } else if (messageText === 'done_images') {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: `${conv.boq_images.length} BOQ image(s) saved.\n\nNow please send your Specification file (PDF only).`,
      };
      conv.state = 'awaiting_spec';
    } else if (messageText === 'more_images') {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: 'Go ahead, send your next image.',
      };
    } else {
      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: 'Please send an image or tap Done.',
        buttons: [
          { id: 'more_images', title: 'Send More' },
          { id: 'done_images', title: 'Done' },
        ],
      };
    }
    break;
  }

  // ---- AWAITING SPEC ----
  case 'awaiting_spec': {
    if (messageType === 'document' &&
        (mediaMimeType === 'application/pdf' || mediaFileName.endsWith('.pdf'))) {
      conv.spec_media_id = mediaId;
      conv.spec_filename = mediaFileName;
      conv.spec_mime_type = mediaMimeType;

      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: 'Spec file received.\n\nWould you like to provide client details?',
        buttons: [
          { id: 'client_yes', title: 'Yes' },
          { id: 'client_skip', title: 'Skip' },
        ],
      };
      conv.state = 'awaiting_client_choice';
    } else {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: 'Please send a PDF file for the specification.',
      };
    }
    break;
  }

  // ---- AWAITING CLIENT CHOICE ----
  case 'awaiting_client_choice': {
    if (messageText === 'client_yes') {
      action = 'send_flow';
      payload = {
        to: senderPhone,
        flow_id: CLIENT_FLOW_ID,
        flow_cta: 'Enter Client Details',
        body: 'Please fill in the client information.',
        screen: 'CLIENT_DETAILS',
      };
      conv.state = 'awaiting_client_flow';
    } else if (messageText === 'client_skip') {
      conv.client_data = {
        name: 'WhatsApp Client',
        company_name: 'WhatsApp Client',
      };
      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: 'Client details skipped.\n\nWould you like to provide project details?',
        buttons: [
          { id: 'project_yes', title: 'Yes' },
          { id: 'project_skip', title: 'Skip' },
        ],
      };
      conv.state = 'awaiting_project_choice';
    } else {
      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: 'Would you like to provide client details?',
        buttons: [
          { id: 'client_yes', title: 'Yes' },
          { id: 'client_skip', title: 'Skip' },
        ],
      };
    }
    break;
  }

  // ---- AWAITING CLIENT FLOW RESPONSE ----
  case 'awaiting_client_flow': {
    if (flowResponseData) {
      conv.client_data = {
        name: flowResponseData.client_name || 'WhatsApp Client',
        company_name: flowResponseData.company_name || 'WhatsApp Client',
        email: flowResponseData.client_email || null,
        phone: flowResponseData.client_phone || null,
        address: flowResponseData.client_address || null,
      };
      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: 'Client details saved.\n\nWould you like to provide project details?',
        buttons: [
          { id: 'project_yes', title: 'Yes' },
          { id: 'project_skip', title: 'Skip' },
        ],
      };
      conv.state = 'awaiting_project_choice';
    } else {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: 'Please complete the client details form.',
      };
    }
    break;
  }

  // ---- AWAITING PROJECT CHOICE ----
  case 'awaiting_project_choice': {
    if (messageText === 'project_yes') {
      action = 'send_flow';
      payload = {
        to: senderPhone,
        flow_id: PROJECT_FLOW_ID,
        flow_cta: 'Enter Project Details',
        body: 'Please fill in the project information.',
        screen: 'PROJECT_DETAILS',
      };
      conv.state = 'awaiting_project_flow';
    } else if (messageText === 'project_skip') {
      const today = new Date().toISOString().split('T')[0];
      conv.project_data = {
        project_name: `WhatsApp Project ${Date.now()}`,
        city: 'Riyadh',
        country: 'KSA',
        due_date: today,
      };
      action = 'send_flow';
      payload = {
        to: senderPhone,
        flow_id: CONFIG_FLOW_ID,
        flow_cta: 'Configure Quotation',
        body: 'Project details skipped.\n\nPlease configure your quotation settings.',
        screen: 'QUOTATION_CONFIG',
      };
      conv.state = 'awaiting_config_flow';
    } else {
      action = 'send_buttons';
      payload = {
        to: senderPhone,
        body: 'Would you like to provide project details?',
        buttons: [
          { id: 'project_yes', title: 'Yes' },
          { id: 'project_skip', title: 'Skip' },
        ],
      };
    }
    break;
  }

  // ---- AWAITING PROJECT FLOW RESPONSE ----
  case 'awaiting_project_flow': {
    if (flowResponseData) {
      conv.project_data = {
        project_name: flowResponseData.project_name || `WhatsApp Project ${Date.now()}`,
        city: flowResponseData.city || 'Riyadh',
        country: flowResponseData.country || 'KSA',
        due_date: flowResponseData.due_date || new Date().toISOString().split('T')[0],
      };
      action = 'send_flow';
      payload = {
        to: senderPhone,
        flow_id: CONFIG_FLOW_ID,
        flow_cta: 'Configure Quotation',
        body: 'Project details saved.\n\nPlease configure your quotation settings.',
        screen: 'QUOTATION_CONFIG',
      };
      conv.state = 'awaiting_config_flow';
    } else {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: 'Please complete the project details form.',
      };
    }
    break;
  }

  // ---- AWAITING CONFIG FLOW RESPONSE ----
  case 'awaiting_config_flow': {
    if (flowResponseData) {
      conv.quotation_config = {
        service_option: parseInt(flowResponseData.service_option) || 1,
        margin_percent: parseFloat(flowResponseData.margin_percent) || 0,
        payment_terms_text: flowResponseData.payment_terms || null,
        subject: flowResponseData.subject || null,
      };
      conv.state = 'executing';
      action = 'execute_pipeline';
      payload = {
        senderPhone,
        conversation: JSON.parse(JSON.stringify(conv)),
        config: {
          WHATSAPP_PHONE_NUMBER_ID,
          WHATSAPP_ACCESS_TOKEN,
          BACKEND_API_URL,
          BACKEND_AUTH_TOKEN,
        },
      };
    } else {
      action = 'send_text';
      payload = {
        to: senderPhone,
        text: 'Please complete the quotation configuration form.',
      };
    }
    break;
  }

  // ---- EXECUTING (pipeline in progress) ----
  case 'executing': {
    action = 'send_text';
    payload = {
      to: senderPhone,
      text: 'Your quotation is still being processed. Please wait...',
    };
    break;
  }

  // ---- DONE ----
  case 'done': {
    conv.state = 'awaiting_confirm';
    action = 'send_buttons';
    payload = {
      to: senderPhone,
      body: 'Would you like to generate another quotation?',
      buttons: [
        { id: 'yes', title: 'Yes' },
        { id: 'no', title: 'No' },
      ],
    };
    break;
  }

  // ---- DEFAULT: reset to new ----
  default: {
    conv.state = 'awaiting_confirm';
    action = 'send_buttons';
    payload = {
      to: senderPhone,
      body: 'Welcome! Would you like to generate a quotation?',
      buttons: [
        { id: 'yes', title: 'Yes' },
        { id: 'no', title: 'No' },
      ],
    };
    break;
  }
}

// Build WhatsApp API body for message-sending actions
let whatsappBody = null;
if (action === 'send_text') {
  whatsappBody = {
    messaging_product: 'whatsapp',
    to: payload.to,
    type: 'text',
    text: { body: payload.text },
  };
} else if (action === 'send_buttons') {
  whatsappBody = {
    messaging_product: 'whatsapp',
    to: payload.to,
    type: 'interactive',
    interactive: {
      type: 'button',
      body: { text: payload.body },
      action: {
        buttons: payload.buttons.map(b => ({
          type: 'reply',
          reply: { id: b.id, title: b.title },
        })),
      },
    },
  };
} else if (action === 'send_flow') {
  whatsappBody = {
    messaging_product: 'whatsapp',
    to: payload.to,
    type: 'interactive',
    interactive: {
      type: 'flow',
      body: { text: payload.body },
      action: {
        name: 'flow',
        parameters: {
          flow_message_version: '3',
          flow_id: payload.flow_id,
          flow_cta: payload.flow_cta,
          mode: 'published',
          flow_action: 'navigate',
          flow_action_payload: {
            screen: payload.screen,
          },
        },
      },
    },
  };
}

return [{
  json: {
    action,
    payload,
    whatsappBody,
    whatsappUrl: WA_URL,
    config: {
      WHATSAPP_PHONE_NUMBER_ID,
      WHATSAPP_ACCESS_TOKEN,
    },
  }
}];

// ============================================================
// Node 11: Execute Pipeline
// Full pipeline: download files, create client/project,
// upload, run pipeline, poll, send quotation result.
// ============================================================

const input = $input.first().json;
const { senderPhone, conversation: conv, config } = input.payload;
const {
  WHATSAPP_PHONE_NUMBER_ID, WHATSAPP_ACCESS_TOKEN,
  BACKEND_API_URL, BACKEND_AUTH_TOKEN
} = config;

const WA_URL = `https://graph.facebook.com/v21.0/${WHATSAPP_PHONE_NUMBER_ID}/messages`;
const waHeaders = {
  'Authorization': `Bearer ${WHATSAPP_ACCESS_TOKEN}`,
  'Content-Type': 'application/json',
};
const apiHeaders = {
  'Authorization': `Bearer ${BACKEND_AUTH_TOKEN}`,
  'Content-Type': 'application/json',
};

// ---------- helpers ----------

async function sendText(text) {
  await fetch(WA_URL, {
    method: 'POST',
    headers: waHeaders,
    body: JSON.stringify({
      messaging_product: 'whatsapp',
      to: senderPhone,
      type: 'text',
      text: { body: text },
    }),
  });
}

async function sendDocument(url, filename, caption) {
  await fetch(WA_URL, {
    method: 'POST',
    headers: waHeaders,
    body: JSON.stringify({
      messaging_product: 'whatsapp',
      to: senderPhone,
      type: 'document',
      document: { link: url, filename: filename, caption: caption },
    }),
  });
}

async function downloadMedia(mediaId) {
  // Step 1: get media URL
  const metaResp = await fetch(
    `https://graph.facebook.com/v21.0/${mediaId}`,
    { headers: { 'Authorization': `Bearer ${WHATSAPP_ACCESS_TOKEN}` } }
  );
  if (!metaResp.ok) throw new Error(`Media metadata failed: ${metaResp.status}`);
  const meta = await metaResp.json();

  // Step 2: download binary
  const fileResp = await fetch(meta.url, {
    headers: { 'Authorization': `Bearer ${WHATSAPP_ACCESS_TOKEN}` },
  });
  if (!fileResp.ok) throw new Error(`Media download failed: ${fileResp.status}`);
  return Buffer.from(await fileResp.arrayBuffer());
}

async function uploadFile(url, fieldName, buf, filename, mimeType) {
  const boundary = '----n8nBoundary' + Date.now();
  const body = Buffer.concat([
    Buffer.from(
      `--${boundary}\r\n` +
      `Content-Disposition: form-data; name="${fieldName}"; filename="${filename}"\r\n` +
      `Content-Type: ${mimeType}\r\n\r\n`
    ),
    buf,
    Buffer.from(`\r\n--${boundary}--\r\n`),
  ]);
  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${BACKEND_AUTH_TOKEN}`,
      'Content-Type': `multipart/form-data; boundary=${boundary}`,
    },
    body,
  });
  if (!resp.ok) throw new Error(`Upload to ${url} failed: ${await resp.text()}`);
  return resp.json();
}

async function uploadImages(url, buffers) {
  const boundary = '----n8nBoundary' + Date.now();
  const parts = [];
  for (let i = 0; i < buffers.length; i++) {
    const { buffer, mimeType } = buffers[i];
    const ext = mimeType.includes('png') ? 'png' : 'jpg';
    parts.push(Buffer.from(
      `--${boundary}\r\n` +
      `Content-Disposition: form-data; name="files"; filename="boq_image_${i + 1}.${ext}"\r\n` +
      `Content-Type: ${mimeType}\r\n\r\n`
    ));
    parts.push(buffer);
    parts.push(Buffer.from('\r\n'));
  }
  parts.push(Buffer.from(`--${boundary}--\r\n`));
  const body = Buffer.concat(parts);
  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${BACKEND_AUTH_TOKEN}`,
      'Content-Type': `multipart/form-data; boundary=${boundary}`,
    },
    body,
  });
  if (!resp.ok) throw new Error(`Image upload failed: ${await resp.text()}`);
  return resp.json();
}

async function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// ---------- main pipeline ----------

try {
  // 1. Notify user
  await sendText('Processing your quotation... This may take a few minutes.');

  // 2. Create client
  const clientResp = await fetch(`${BACKEND_API_URL}/clients`, {
    method: 'POST',
    headers: apiHeaders,
    body: JSON.stringify(conv.client_data),
  });
  if (!clientResp.ok) throw new Error(`Create client failed: ${await clientResp.text()}`);
  const client = await clientResp.json();
  const clientId = client.id;

  // 3. Create project
  const projectBody = {
    project_name: conv.project_data.project_name,
    client_id: clientId,
    city: conv.project_data.city,
    country: conv.project_data.country,
    due_date: conv.project_data.due_date,
  };
  const projectResp = await fetch(`${BACKEND_API_URL}/projects`, {
    method: 'POST',
    headers: apiHeaders,
    body: JSON.stringify(projectBody),
  });
  if (!projectResp.ok) throw new Error(`Create project failed: ${await projectResp.text()}`);
  const project = await projectResp.json();
  const projectId = project.id;

  await sendText('Client and project created. Uploading files...');

  // 4. Download & upload BOQ
  if (conv.boq_media_type === 'images') {
    const imageBuffers = [];
    for (const img of conv.boq_images) {
      const buf = await downloadMedia(img.media_id);
      imageBuffers.push({ buffer: buf, mimeType: img.mime_type });
    }
    await uploadImages(
      `${BACKEND_API_URL}/projects/${projectId}/boq/upload-images`,
      imageBuffers
    );
  } else {
    const boqBuf = await downloadMedia(conv.boq_media_id);
    const endpoint = conv.boq_media_type === 'pdf' ? 'upload-pdf' : 'upload';
    const filename = conv.boq_filename ||
      (conv.boq_media_type === 'pdf' ? 'boq.pdf' : 'boq.xlsx');
    const mimeType = conv.boq_mime_type ||
      (conv.boq_media_type === 'pdf'
        ? 'application/pdf'
        : 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
    await uploadFile(
      `${BACKEND_API_URL}/projects/${projectId}/boq/${endpoint}`,
      'file', boqBuf, filename, mimeType
    );
  }

  // 5. Download & upload spec
  const specBuf = await downloadMedia(conv.spec_media_id);
  await uploadFile(
    `${BACKEND_API_URL}/projects/${projectId}/spec/upload`,
    'file', specBuf,
    conv.spec_filename || 'specification.pdf',
    'application/pdf'
  );

  await sendText('Files uploaded. Configuring quotation...');

  // 6. Save quotation config
  const qcBody = {
    client_name: conv.client_data.name,
    client_address: conv.client_data.address || conv.client_data.company_name,
    subject: conv.quotation_config.subject,
    service_option: conv.quotation_config.service_option,
    margin_percent: conv.quotation_config.margin_percent,
    payment_terms_text: conv.quotation_config.payment_terms_text,
    inclusion_answers: {},
  };
  const cfgResp = await fetch(
    `${BACKEND_API_URL}/projects/${projectId}/pipeline/quotation-config`,
    { method: 'POST', headers: apiHeaders, body: JSON.stringify(qcBody) }
  );
  if (!cfgResp.ok) throw new Error(`Save config failed: ${await cfgResp.text()}`);

  // 7. Start pipeline
  const runResp = await fetch(
    `${BACKEND_API_URL}/projects/${projectId}/pipeline/run`,
    { method: 'POST', headers: apiHeaders }
  );
  if (!runResp.ok) throw new Error(`Start pipeline failed: ${await runResp.text()}`);

  await sendText('Pipeline started. Generating quotation...');

  // 8. Poll status (every 15 s, max 60 attempts = 15 min)
  let status = 'running';
  let attempts = 0;
  const MAX = 60;
  while (status === 'running' && attempts < MAX) {
    await sleep(15000);
    const sResp = await fetch(
      `${BACKEND_API_URL}/projects/${projectId}/pipeline/status`,
      { headers: { 'Authorization': `Bearer ${BACKEND_AUTH_TOKEN}` } }
    );
    if (!sResp.ok) throw new Error(`Status poll failed: ${sResp.status}`);
    const sData = await sResp.json();
    status = sData.status;
    attempts++;

    if (status === 'failed') {
      throw new Error(
        `Pipeline failed at step "${sData.error_step}": ${sData.error_message}`
      );
    }
  }
  if (status !== 'completed') {
    throw new Error('Pipeline timed out after 15 minutes.');
  }

  // 9. Get download URL
  const dlResp = await fetch(
    `${BACKEND_API_URL}/projects/${projectId}/quotation/download?format=docx`,
    { headers: { 'Authorization': `Bearer ${BACKEND_AUTH_TOKEN}` } }
  );
  if (!dlResp.ok) throw new Error(`Download URL failed: ${await dlResp.text()}`);
  const dlData = await dlResp.json();

  // 10. Send document to user
  await sendDocument(dlData.url, dlData.file_name, 'Your quotation is ready!');
  await sendText(
    'Your quotation has been generated successfully!\n' +
    'Send any message to start a new one.'
  );

  // 11. Reset conversation
  const globalData = $getWorkflowStaticData('global');
  if (globalData.conversations?.[senderPhone]) {
    globalData.conversations[senderPhone] = { state: 'new' };
  }

  return [{ json: { success: true, projectId } }];

} catch (error) {
  await sendText(
    'Sorry, something went wrong while generating your quotation.\n\n' +
    `Error: ${error.message}\n\nPlease try again.`
  );

  // Reset conversation
  const globalData = $getWorkflowStaticData('global');
  if (globalData.conversations?.[senderPhone]) {
    globalData.conversations[senderPhone] = { state: 'new' };
  }

  return [{ json: { success: false, error: error.message } }];
}
